class UserBadge extends React.PureComponent {
  render() {
    const { name, role, avatarUrl } = this.props;
    return (
      <div className="badge">
        <img src={avatarUrl} alt={name} />
        <span>{name}</span>
        <span className="role">{role}</span>
      </div>
    );
  }
}
